  ('pukao-d0d1b9a2-moex-00129', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列何者非為查核人員取得客戶書面聲明的目的？', '["受查者藉此表明及確認其對投資、理財等重大事項之意向", "針對內部控制制度缺失及其他事項提出說明及改進建議", "提醒受查者應對報表允當性負責", "避免查核人員誤解受查者之口頭聲明，故採較精確之書面形式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "af6af81c720a", "answer_pdf_sha1": "d8dfea9411c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00130', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '查核人員評估內部稽核職能所執行工作及所達成結論之品質時，最不可能執行之查核程序為下列 何者？', '["對部分規劃採用之內部稽核工作予以重新執行", "查詢內部稽核職能之適當人員", "觀察內部稽核職能執行之程序", "必要時寄發第三方詢證函"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "af6af81c720a", "answer_pdf_sha1": "d8dfea9411c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
