  ('pukao-d0d1b9a2-moex-00132', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '關於查核財務報表對舞弊之考量，查核人員向受查者取得書面聲明事項之內容，下列敘述何者錯誤？', '["已知或疑似之舞弊如涉及管理階層、內部控制制度中扮演重要角色之員工或其他具重大影響人 員，皆已告知", "財務報表可能因舞弊而導致重大不實表達風險之評估結果，皆已告知", "設計並執行內部控制制度以防止或偵查舞弊，係公司內部稽核職能的責任", "離職與現職員工、分析師、主管機關或其他人員，提供任何影響財務報表表達之疑似或傳聞舞 弊，皆已告知"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "af6af81c720a", "answer_pdf_sha1": "d8dfea9411c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00133', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '查核人員對財務報表所依據之繼續經營會計基礎產生疑慮時，通常不會採行下列何項查核程序？', '["取得管理階層有關未來因應措施之書面聲明", "確認內部人員績效考核系統有無重大改變之期後事項", "評估關係人或第三者對受查者所作財務支援安排之有效性及可行性", "查閱借款及其他債務合約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "af6af81c720a", "answer_pdf_sha1": "d8dfea9411c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
